// MARK: - BiometricAuthManager

class BiometricAuthManager {
    
    static let shared = BiometricAuthManager()
    
    private let keychainService = "com.myapp.biometric"
    private let keychainAccount = "biometricAuthenticated"
    private let biometricEnabledKey = "biometricAuthEnabled"
    
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum BiometricError: Error, LocalizedError {
        case notAvailable
        case notEnrolled
        case authenticationFailed
        case userCancelled
        case userFallback
        case lockout
        case unknown(Error)
        
        var errorDescription: String? {
            switch self {
            case .notAvailable:
                return "Biometric authentication is not available on this device."
            case .notEnrolled:
                return "No biometric data is enrolled. Please set up Face ID or Touch ID in Settings."
            case .authenticationFailed:
                return "Authentication failed. Please try again."
            case .userCancelled:
                return "Authentication was cancelled."
            case .userFallback:
                return "User chose to enter password."
            case .lockout:
                return "Biometric authentication is locked due to too many failed attempts. Please use your password."
            case .unknown(let error):
                return error.localizedDescription
            }
        }
    }
    
    // MARK: - Biometric Type Detection
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        switch context.biometryType {
        case .faceID:
            return .faceID
        case .touchID:
            return .touchID
        case .opticID:
            return .faceID // Treat opticID similar to faceID for UI purposes
        @unknown default:
            return .none
        }
    }
    
    var biometricTypeString: String {
        switch biometricType {
        case .faceID:
            return "Face ID"
        case .touchID:
            return "Touch ID"
        case .none:
            return "Biometrics"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    var isBiometricEnabled: Bool {
        get { UserDefaults.standard.bool(forKey: biometricEnabledKey) }
        set { UserDefaults.standard.set(newValue, forKey: biometricEnabledKey) }
    }
    
    // MARK: - Keychain Operations
    
    func setAuthenticatedFlag(_ authenticated: Bool) {
        let data = Data(authenticated ? [1] : [0])
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount
        ]
        
        SecItemDelete(query as CFDictionary)
        
        if authenticated {
            var newItem = query
            newItem[kSecValueData as String] = data
            newItem[kSecAttrAccessible as String] = kSecAttrAccessibleWhenUnlockedThisDeviceOnly
            SecItemAdd(newItem as CFDictionary, nil)
        }
    }
    
    func isUserAuthenticated() -> Bool {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: keychainService,
            kSecAttrAccount as String: keychainAccount,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess,
              let data = result as? Data,
              let firstByte = data.first else {
            return false
        }
        
        return firstByte == 1
    }
    
    func clearAuthentication() {
        setAuthenticatedFlag(false)
        isBiometricEnabled = false
    }
    
    // MARK: - Authentication
    
    func authenticate(reason: String? = nil, completion: @escaping (Result<Void, BiometricError>) -> Void) {
        let context = LAContext()
        context.localizedFallbackTitle = "Enter Password"
        context.localizedCancelTitle = "Cancel"
        
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let laError = error as? LAError {
                switch laError.code {
                case .biometryNotAvailable:
                    completion(.failure(.notAvailable))
                case .biometryNotEnrolled:
                    completion(.failure(.notEnrolled))
                case .biometryLockout:
                    completion(.failure(.lockout))
                default:
                    completion(.failure(.unknown(laError)))
                }
            } else {
                completion(.failure(.notAvailable))
            }
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricTypeString) to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: authReason) { success, authError in
            DispatchQueue.main.async {
                if success {
                    self.setAuthenticatedFlag(true)
                    self.isBiometricEnabled = true
                    completion(.success(()))
                } else if let laError = authError as? LAError {
                    switch laError.code {
                    case .userCancel:
                        completion(.failure(.userCancelled))
                    case .userFallback:
                        completion(.failure(.userFallback))
                    case .authenticationFailed:
                        completion(.failure(.authenticationFailed))
                    case .biometryLockout:
                        completion(.failure(.lockout))
                    default:
                        completion(.failure(.unknown(laError)))
                    }
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
    
    func authenticateWithDevicePasscode(reason: String? = nil, completion: @escaping (Result<Void, BiometricError>) -> Void) {
        let context = LAContext()
        let authReason = reason ?? "Enter your device passcode to access your account"
        
        context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: authReason) { success, error in
            DispatchQueue.main.async {
                if success {
                    self.setAuthenticatedFlag(true)
                    completion(.success(()))
                } else {
                    completion(.failure(.authenticationFailed))
                }
            }
        }
    }
}

