        super.viewDidLoad()
        setupUI()
        
        title = "Home"
        navigationItem.hidesBackButton = true
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        let biometricTypeName = authManager.biometricTypeString
        biometricToggleLabel.text = "Enable \(biometricTypeName)"
        biometricToggle.isOn = authManager.isBiometricEnabled
        biometricToggle.addTarget(self, action: #selector(biometricToggleChanged), for: .valueChanged)
        
        infoLabel.text = authManager.isBiometricEnabled
            ? "\(biometricTypeName) is enabled for quick sign-in."
            : "Enable \(biometricTypeName) for faster access next time."
        
        let toggleStack = UIStackView(arrangedSubviews: [biometricToggleLabel, biometricToggle])
        toggleStack.axis = .horizontal
        toggleStack.spacing = 12
        toggleStack.translatesAutoresizingMaskIntoConstraints = false
        
        // Hide toggle if biometrics not available
        if !authManager.isBiometricAvailable {
            toggleStack.isHidden = true
            infoLabel.text = "Biometric authentication is not available on this device."
        }
        
        view.addSubview(welcomeLabel)
        view.addSubview(infoLabel)
        view.addSubview(toggleStack)
        view.addSubview(logoutButton)
        
        NSLayoutConstraint.activate([
            welcomeLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            welcomeLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -80),
            
            infoLabel.topAnchor.constraint(equalTo: welcomeLabel.bottomAnchor, constant: 12),
            infoLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            infoLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            
            toggleStack.topAnchor.constraint(equalTo: infoLabel.bottomAnchor, constant: 32),
            toggleStack.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            
            logoutButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -32),
            logoutButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            logoutButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            logoutButton.heightAnchor.constraint(equalToConstant: 50)
        ])
        
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
    }
    
    @objc private func biometricToggleChanged(_ sender: UISwitch) {
        if sender.isOn {
            authManager.authenticate(reason: "Verify your identity to enable \(authManager.biometricTypeString)") { [weak self] result in
                switch result {
                case .success:
                    self?.authManager.isBiometricEnabled = true
                    self?.infoLabel.text = "\(self?.authManager.biometricTypeString ?? "Biometrics") is enabled for quick sign-in."
                case .failure:
                    sender.setOn(false, animated: true)
                }
            }
        } else {
            authManager.isBiometricEnabled = false
            infoLabel.text = "Enable \(authManager.biometricTypeString) for faster access next time."
        }
    }
    
    @objc private func logoutTapped() {
        let alert = UIAlertController(title: "Sign Out", message: "Are you sure you want to sign out?", preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Sign Out", style: .destructive) { [weak self] _ in
            self?.authManager.setAuthenticatedFlag(false)
            self?.navigateToLogin()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func navigateToLogin() {
        if let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
           let window = windowScene.windows.first {
            UIView.transition(with: window, duration: 0.3, options: .transitionCrossDissolve) {
                window.rootViewController = LoginViewController()
            }
        }
    }
}

// MARK: - AppFlowController

class AppFlowController {
    
    static let shared = AppFlowController()
    
    private let authManager = BiometricAuthManager.shared
    
    private init() {}
    
    func determineRootViewController() -> UIViewController {
        if authManager.isUserAuthenticated() && authManager.isBiometricEnabled && authManager.isBiometricAvailable {
            // User was previously authenticated and biometrics enabled
            // Show login screen but it will auto-trigger biometric auth in viewDidAppear
            return LoginViewController()
        } else if authManager.isUserAuthenticated() && !authManager.isBiometricEnabled {
            // Authenticated but biometrics not enabled - go straight to main
            return UINavigationController(rootViewController: MainViewController())
        } else {
            // Not authenticated - show login
            return LoginViewController()
        }
    }
}

// MARK: - SceneDelegate

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }
        
        let window = UIWindow(windowScene: windowScene)
        window.rootViewController = AppFlowController.shared.determineRootViewController()
        window.makeKeyAndVisible()
        self.window = window
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Optional: Re-authenticate when app becomes active after being in background
    }
    
    func sceneWillResignActive(_ scene: UIScene) {
        // Optional: Add a privacy screen/blur when app goes to background
    }
}

